-- Classify Sicilian Defense puzzles
UPDATE puzzles SET opening = 'Sicilian Defense', subset = 'Sicilian Najdorf', variation = 'Najdorf Variation' WHERE openingName LIKE '%Sicilian Najdorf%';
UPDATE puzzles SET opening = 'Sicilian Defense', subset = 'Sicilian Accelerated Dragon', variation = 'Accelerated Dragon' WHERE openingName LIKE '%Sicilian Accelerated Dragon%';
UPDATE puzzles SET opening = 'Sicilian Defense', subset = 'Sicilian Closed', variation = 'Closed Variation' WHERE openingName LIKE '%Sicilian Closed%';
UPDATE puzzles SET opening = 'Sicilian Defense', subset = 'Sicilian Defense', variation = 'Main Line' WHERE openingName LIKE '%Sicilian%' AND opening IS NULL;

-- Classify Italian Game puzzles
UPDATE puzzles SET opening = 'Italian Game', subset = 'Italian Game Giuoco Piano', variation = 'Giuoco Piano' WHERE openingName LIKE '%Italian Game Giuoco Piano%';
UPDATE puzzles SET opening = 'Italian Game', subset = 'Italian Game Two Knights Defense', variation = 'Two Knights Defense' WHERE openingName LIKE '%Italian Game Two Knights Defense%';
UPDATE puzzles SET opening = 'Italian Game', subset = 'Italian Game', variation = 'Main Line' WHERE openingName LIKE '%Italian Game%' AND opening IS NULL;

-- Classify French Defense puzzles
UPDATE puzzles SET opening = 'French Defense', subset = 'French Defense', variation = 'Main Line' WHERE openingName LIKE '%French Defense%' AND opening IS NULL;

-- Classify Four Knights puzzles
UPDATE puzzles SET opening = 'Four Knights', subset = 'Four Knights Game', variation = 'Four Knights Game' WHERE openingName LIKE '%Four Knights Game%';
UPDATE puzzles SET opening = 'Four Knights', subset = 'Four Knights Scotch', variation = 'Scotch Game' WHERE openingName LIKE '%Four Knights Scotch%';
UPDATE puzzles SET opening = 'Four Knights', subset = 'Four Knights', variation = 'Main Line' WHERE openingName LIKE '%Four Knights%' AND opening IS NULL;

-- Classify remaining puzzles as Opening
UPDATE puzzles SET opening = 'Opening', subset = 'Unclassified', variation = 'Unknown' WHERE opening IS NULL OR opening = '';

